class Solution:
    def minProcessingTime(self, processorTime: List[int], tasks: List[int]) -> int:
        processorTime.sort()
        tasks.sort(reverse=True)
        n = len(processorTime)
        res = 0
        for i in range(n):
            start_time = processorTime[i]
            # Assign 4 largest tasks to each processor
            for j in range(4 * i, 4 * (i + 1)):
                res = max(res, start_time + tasks[j])
        return res
